## Objective
Create the customer home page that loads categories and menu items, supports cart actions, and links to checkout and order tracking.

## Files to write

### frontend/src/pages/HomePage.tsx
```tsx
import { useEffect, useMemo, useState } from 'react';
import { Link } from 'react-router-dom';
import { Category, MenuItem } from '../types';

export default function HomePage() {
  const [categories, setCategories] = useState<Category[]>([]);
  const [items, setItems] = useState<MenuItem[]>([]);
  const [selectedCategoryId, setSelectedCategoryId] = useState<number | null>(null);
  const [cart, setCart] = useState<Record<number, number>>({});

  useEffect(() => {
    Promise.all([fetch('/api/categories').then(r => r.json()), fetch('/api/menu-items').then(r => r.json())])
      .then(([cats, menu]) => {
        setCategories(cats);
        setItems(menu);
        setSelectedCategoryId(cats[0]?.id ?? null);
      });
  }, []);

  const visibleItems = useMemo(() => items.filter(i => selectedCategoryId === null || i.category_id === selectedCategoryId), [items, selectedCategoryId]);
  const cartCount = Object.values(cart).reduce((a, b) => a + b, 0);

  return <div style={{ padding: 16, fontFamily: 'system-ui', background: '#fff8ef', minHeight: '100vh' }}>
    <h1 style={{ margin: 0 }}>Pop-Up Food Cart</h1>
    <div style={{ display: 'flex', gap: 8, overflowX: 'auto', margin: '16px 0' }}>
      {categories.map(c => <button key={c.id} onClick={() => setSelectedCategoryId(c.id)} style={{ padding: '8px 12px', borderRadius: 999, border: '1px solid #f59e0b', background: selectedCategoryId === c.id ? '#f59e0b' : 'white' }}>{c.name}</button>)}
    </div>
    <div style={{ display: 'grid', gap: 12 }}>
      {visibleItems.map(item => <div key={item.id} style={{ background: 'white', borderRadius: 16, padding: 12, boxShadow: '0 1px 6px rgba(0,0,0,0.08)' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', gap: 12 }}>
          <div>
            <div style={{ fontWeight: 700 }}>{item.name}</div>
            <div style={{ fontSize: 14, color: '#555' }}>{item.description}</div>
            <div style={{ marginTop: 8 }}>${item.price.toFixed(2)}</div>
          </div>
          <button onClick={() => setCart(prev => ({ ...prev, [item.id]: (prev[item.id] ?? 0) + 1 }))} style={{ alignSelf: 'center', padding: '8px 12px', borderRadius: 12, background: '#f59e0b', color: 'white', border: 0 }}>Add</button>
        </div>
      </div>)}
    </div>
    <div style={{ position: 'sticky', bottom: 16, marginTop: 16, background: '#111827', color: 'white', padding: 12, borderRadius: 16, display: 'flex', justifyContent: 'space-between' }}>
      <span>{cartCount} in cart</span>
      <Link to="/checkout" style={{ color: 'white' }}>Checkout</Link>
    </div>
    <div style={{ marginTop: 12 }}><Link to="/track" style={{ color: '#b45309' }}>Track order</Link></div>
  </div>;
}
```

## Objective
Create the checkout page that submits an order and shows the confirmation with order number.

## Files to write

### frontend/src/pages/CheckoutPage.tsx
```tsx
import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { CreateOrderInput } from '../types';

export default function CheckoutPage() {
  const navigate = useNavigate();
  const [customerName, setCustomerName] = useState('');
  const [customerPhone, setCustomerPhone] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [orderNumber, setOrderNumber] = useState('');

  async function submitOrder() {
    setSubmitting(true);
    const payload: CreateOrderInput = { customer_name: customerName || null, customer_phone: customerPhone || null, items: [] };
    const res = await fetch('/api/orders', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
    const data = await res.json();
    setOrderNumber(data.order_number);
    setSubmitting(false);
  }

  if (orderNumber) return <div style={{ padding: 16 }}><h1>Order confirmed</h1><p>Your order number is {orderNumber}</p><button onClick={() => navigate('/track')}>Track status</button></div>;

  return <div style={{ padding: 16 }}>
    <h1>Checkout</h1>
    <input value={customerName} onChange={e => setCustomerName(e.target.value)} placeholder="Name" />
    <input value={customerPhone} onChange={e => setCustomerPhone(e.target.value)} placeholder="Phone" />
    <button disabled={submitting} onClick={submitOrder}>{submitting ? 'Submitting...' : 'Submit order'}</button>
  </div>;
}
```

## Objective
Create the customer order tracking page that polls the order status in real time.

## Files to write

### frontend/src/pages/TrackOrderPage.tsx
```tsx
import { useEffect, useState } from 'react';
import { Order } from '../types';

export default function TrackOrderPage() {
  const [orderId, setOrderId] = useState('');
  const [order, setOrder] = useState<Order | null>(null);

  useEffect(() => {
    if (!orderId) return;
    const timer = setInterval(async () => {
      const res = await fetch(`/api/orders/${orderId}`);
      if (res.ok) setOrder(await res.json());
    }, 3000);
    return () => clearInterval(timer);
  }, [orderId]);

  return <div style={{ padding: 16 }}>
    <h1>Track Order</h1>
    <input value={orderId} onChange={e => setOrderId(e.target.value)} placeholder="Order ID" />
    {order && <div style={{ marginTop: 16 }}>
      <div>Order #{order.order_number}</div>
      <div>Status: {order.status}</div>
    </div>}
  </div>;
}
```

## Objective
Create the admin login page that verifies the PIN before entering the admin panel.

## Files to write

### frontend/src/pages/AdminLoginPage.tsx
```tsx
import { useState } from 'react';
import { useNavigate } from 'react-router-dom';

export default function AdminLoginPage() {
  const navigate = useNavigate();
  const [pin, setPin] = useState('');
  const [error, setError] = useState('');

  async function login() {
    const res = await fetch('/api/settings/verify', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ cart_name: '', opening_time: '', closing_time: '', admin_pin: pin }) });
    const data = await res.json();
    if (data.valid) navigate('/admin'); else setError('Invalid PIN');
  }

  return <div style={{ padding: 16 }}>
    <h1>Admin Login</h1>
    <input value={pin} onChange={e => setPin(e.target.value)} placeholder="PIN" type="password" />
    <button onClick={login}>Enter</button>
    {error && <div>{error}</div>}
  </div>;
}
```

## Objective
Create the admin dashboard page that shows orders, daily summary, and links to management screens.

## Files to write

### frontend/src/pages/AdminDashboardPage.tsx
```tsx
import { useEffect, useState } from 'react';
import { DailySummary, Order } from '../types';

export default function AdminDashboardPage() {
  const [orders, setOrders] = useState<Order[]>([]);
  const [summary, setSummary] = useState<DailySummary | null>(null);

  useEffect(() => {
    fetch('/api/orders').then(r => r.json()).then(setOrders);
    fetch(`/api/reports/daily-summary?date=${new Date().toISOString().slice(0, 10)}`).then(r => r.json()).then(setSummary);
  }, []);

  return <div style={{ padding: 16 }}>
    <h1>Admin Dashboard</h1>
    {summary && <div>Today: {summary.order_count} orders, ${summary.total_sales.toFixed(2)}</div>}
    <div style={{ marginTop: 16 }}>
      {orders.map(order => <div key={order.id}>{order.order_number} — {order.status}</div>)}
    </div>
  </div>;
}
```

